  ('generalpolice-94737317-moex-00217', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依司法院大法官解釋，人民之土地如屬既成道路，有關其財產權之保障，下列敘述何者錯誤？', '["政府對於既成道路用地，應訂定期限籌措財源，逐年辦理徵收補償", "既成道路如長期未徵收，土地所有權人得就其所受特別犧牲請求徵收補償", "政府埋設地下設施於未依法徵收的既成道路中，造成土地所有人的特別犧牲，土地所有人得請求相當補償", "私有土地雖屬既成道路，但未經都市計畫劃為道路用地，不得用以抵繳遺產稅，並未牴觸憲法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00218', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依司法院釋字第721號解釋意旨，落實民主選舉之基本原則，不包括下列何者？', '["民意政治", "責任政治", "主權在民", "公民投票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00219', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '原住民族工作權保障法及政府採購法規定，關於政府採購得標廠商於國內員工總人數逾一百人者，應於履 約期間僱用原住民，人數不得低於總人數百分之一，進用原住民人數未達標準者，應向原住民族綜合發展 基金之就業基金繳納代金。請問下列何者並非大法官認為此規定合憲之理由？', '["未限制得標廠商之營業自由", "對得標廠商之限制符合比例原則", "對原住民之僱用保障未牴觸平等原則", "國家有保障扶助並促進原住民族發展之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00220', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '憲法增修條文對原住民族地位及政治參與之保障有何具體規定？', '["國家應劃定原住民自治區", "政府機關應任用一定比例之原住民公務員", "行政院應設置原住民族委員會", "立法院應有一定數額之原住民委員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00221', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '憲法第9條規定：「非現役軍人，不受軍事審判」。下列敘述何者正確？', '["只有現役職業軍人犯罪才須受軍事審判，不包括義務役軍人之犯罪", "無論是現役職業軍人、義務役軍人、也不管在軍中是文職或武職之人員，其於戰時犯罪均須受軍事審判", "依現行法制，軍人於非戰時之犯罪， 已無須受軍事審判", "現役軍人犯罪得選擇由軍事法院或刑事法院審判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
